class Solution:
    def maxValue(self, n: int, index: int, maxSum: int) -> int:
        def possible(x):
            left, right = index, n - index - 1
            if x <= index:
                left_sum = (x + 1) * x // 2
            else:
                left_sum = (index + 1) * index // 2 + (x - index) * index
            if x <= right:
                right_sum = (x + 1) * x // 2
            else:
                right_sum = (right + 1) * right // 2 + (x - right) * right
            return left_sum + right_sum + x <= maxSum

        left, right = 1, maxSum
        while left < right:
            mid = (left + right + 1) // 2
            if possible(mid):
                left = mid
            else:
                right = mid - 1
        return left
